const data = this.getWorkflowStaticData('global');
if (!data.processed) data.processed = [];
if (data.processed.includes($json.id)) return [];
data.processed.push($json.id);
return [$json];

const html = $json.textHtml || '';
let text = html
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, '')
  .replace(/\s+/g, ' ')
  .trim();

if (text.length < 500) return [];
if (text.length > 20000) return [];

text = text.substring(0, 8000);
text = text.split(' ').slice(0, 1200).join(' ');

return [{ clean_text: text, id: $json.id }];

const text = $json.clean_text.toLowerCase();
let score = 0;
if (text.includes('funding')) score += 2;
if (text.includes('acquisition')) score += 2;
if (text.includes('launch')) score += 2;
if (text.includes('regulation')) score += 2;
if (text.includes('ai')) score += 1;
if (text.match(/\$\d+/)) score += 1;
if (score < 2) return [];
return [$json];

const content = $json.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  return [];
}

if (parsed.score < 7) return [];

const data = this.getWorkflowStaticData('global');
if (!data.digest) data.digest = [];
if (!data.tokens) data.tokens = { in:0, out:0, exec:0 };

// Track tokens
data.tokens.in += $json.usage?.prompt_tokens || 0;
data.tokens.out += $json.usage?.completion_tokens || 0;
data.tokens.exec += 1;

const formatted = `Score: ${parsed.score}/10\n\n${parsed.summary}`;

data.digest.push(formatted);

return [{ stored:true }];
